import networkx as nx
import threading
from typing import Callable, Dict, List

class Task:
    def __init__(self, name: str, func: Callable):
        self.name = name
        self.func = func

class Scheduler:
    def __init__(self):
        self.graph = nx.DiGraph()
        self.tasks: Dict[str, Task] = {}

    def add_task(self, name: str, func: Callable):
        if name in self.tasks:
            raise ValueError(f"La tarea '{name}' ya existe")
        self.tasks[name] = Task(name, func)
        self.graph.add_node(name)

    def add_dependency(self, task_name: str, dependency_name: str):
        if task_name not in self.tasks:
            raise ValueError(f"La tarea '{task_name}' no existe")
        if dependency_name not in self.tasks:
            raise ValueError(f"La tarea '{dependency_name}' no existe")
        if task_name == dependency_name:
            raise ValueError(f"Una tarea no puede depender de sí misma")
        if self.graph.has_edge(dependency_name, task_name):
            raise ValueError(f"La dependencia entre '{dependency_name}' y '{task_name}' ya existe")
        self.graph.add_edge(dependency_name, task_name)

    def schedule(self):
        if not self.graph:
            raise ValueError("El grafo está vacío")
        if not nx.is_directed_acyclic_graph(self.graph):
            raise ValueError("El grafo tiene ciclos")
        order = list(nx.topological_sort(self.graph))
        for task_name in order:
            task = self.tasks[task_name]
            try:
                threading.Thread(target=task.func).start()
            except Exception as e:
                print(f"Error al ejecutar la tarea '{task_name}': {str(e)}")

# Ejemplo de uso
