from collections import defaultdict, deque

class Scheduler:
    def __init__(self):
        self.graph = defaultdict(list)
        self.in_degree = defaultdict(int)

    def add_task(self, task, dependencies=None):
        if dependencies is None:
            dependencies = []

        # Verificar si la tarea ya existe en el grafo
        if task in self.in_degree:
            raise ValueError("La tarea ya existe en el grafo")

        # Verificar si las dependencias existen en el grafo
        for dependency in dependencies:
            if dependency not in self.in_degree:
                raise ValueError("La dependencia no existe en el grafo")

        # Agregar la tarea al grafo
        self.in_degree[task] = 0
        for dependency in dependencies:
            self.graph[dependency].append(task)
            self.in_degree[task] += 1

    def schedule(self):
        # Verificar si el grafo está vacío
        if not self.in_degree:
            return []

        queue = deque([task for task, degree in self.in_degree.items() if degree == 0])
        scheduled_tasks = []
        visited = set()

        while queue:
            task = queue.popleft()
            visited.add(task)
            scheduled_tasks.append(task)

            for neighbor in self.graph[task]:
                self.in_degree[neighbor] -= 1
                if self.in_degree[neighbor] == 0 and neighbor not in visited:
                    queue.append(neighbor)

        # Verificar si hay un ciclo en el grafo
        if len(scheduled_tasks) != len(self.in_degree):
            raise ValueError("El grafo tiene un ciclo y no se puede programar")

        return scheduled_tasks

    def has_cycle(self):
        # Verificar si el grafo está vacío
        if not self.in_degree:
            return False

        queue = deque([task for task, degree in self.in_degree.items() if degree == 0])
        visited = set()
        current_path = set()

        while queue:
            task = queue.popleft()
            visited.add(task)
            current_path.add(task)

            for neighbor in self.graph[task]:
                if neighbor in current_path:
                    return True
                if neighbor not in visited:
                    queue.append(neighbor)
                    current_path.add(neighbor)

            current_path.remove(task)

        return False

