        self.name = name
        self.func = func

class Scheduler:
    def __init__(self):
        self.graph = nx.DiGraph()
        self.tasks: Dict[str, Task] = {}
        self.executed_tasks: Dict[str, bool] = {}

    def add_task(self, name: str, func: Callable):
        if name in self.tasks:
            raise ValueError(f"La tarea '{name}' ya existe en el grafo")
        self.tasks[name] = Task(name, func)
        self.graph.add_node(name)
        self.executed_tasks[name] = False

    def add_dependency(self, task_name: str, dependency_name: str):
        if task_name not in self.tasks or dependency_name not in self.tasks:
            raise ValueError(f"La tarea '{task_name}' o la dependencia '{dependency_name}' no existen en el grafo")
        self.graph.add_edge(dependency_name, task_name)

    def schedule(self):
        # Verificar si el grafo tiene ciclos
        if not nx.is_directed_acyclic_graph(self.graph):
            cycles = list(nx.simple_cycles(self.graph))
            raise ValueError(f"El grafo tiene ciclos: {cycles}")

        # Obtener el orden topológico de las tareas
        order = list(nx.topological_sort(self.graph))

        # Ejecutar las tareas en orden topológico
        for task_name in order:
            task = self.tasks[task_name]
            if not self.executed_tasks[task_name]:
                threading.Thread(target=task.func).start()
                self.executed_tasks[task_name] = True

    def remove_task(self, name: str):
        if name not in self.tasks:
            raise ValueError(f"La tarea '{name}' no existe en el grafo")
        del self.tasks[name]
        self.graph.remove_node(name)
        del self.executed_tasks[name]

