import sqlite3
from typing import Any, Dict, List

class Campo:
    def __init__(self, nombre: str, tipo: str):
        if not nombre:
            raise ValueError("El nombre del campo no puede ser vacío")
        if not tipo:
            raise ValueError("El tipo del campo no puede ser vacío")
        self.nombre = nombre
        self.tipo = tipo

class Modelo:
    def __init__(self, nombre: str, campos: List[Campo]):
        if not nombre:
            raise ValueError("El nombre del modelo no puede ser vacío")
        if not campos:
            raise ValueError("El modelo debe tener al menos un campo")
        self.nombre = nombre
        self.campos = campos

    def crear_tabla(self, conexion: sqlite3.Connection):
        if not conexion:
            raise ValueError("La conexión a la base de datos no puede ser vacía")
        cursor = conexion.cursor()
        cursor.execute(f"SELECT name FROM sqlite_master WHERE type='table' AND name='{self.nombre}'")
        if not cursor.fetchone():
            campos_sql = ", ".join(f"{campo.nombre} {campo.tipo}" for campo in self.campos)
            cursor.execute(f"CREATE TABLE {self.nombre} (id INTEGER PRIMARY KEY, {campos_sql})")
            conexion.commit()

    def insertar(self, conexion: sqlite3.Connection, datos: Dict[str, Any]):
        if not conexion:
            raise ValueError("La conexión a la base de datos no puede ser vacía")
        if not all(campo.nombre in datos for campo in self.campos):
            raise ValueError("Los datos proporcionados no contienen todos los campos requeridos")
        cursor = conexion.cursor()
        nombres_campos = ", ".join(campo.nombre for campo in self.campos)
        valores = ", ".join("?" for _ in self.campos)
        cursor.execute(f"INSERT INTO {self.nombre} ({nombres_campos}) VALUES ({valores})", [datos[campo.nombre] for campo in self.campos])
        conexion.commit()

    def seleccionar(self, conexion: sqlite3.Connection, condiciones: Dict[str, Any] = None):
        if not conexion:
            raise ValueError("La conexión a la base de datos no puede ser vacía")
        cursor = conexion.cursor()
        if condiciones:
            if not condiciones:
                raise ValueError("Las condiciones no pueden ser vacías")
            condiciones_sql = " AND ".join(f"{nombre} = ?" for nombre in condiciones)
            cursor.execute(f"SELECT * FROM {self.nombre} WHERE {condiciones_sql}", list(condiciones.values()))
        else:
            cursor.execute(f"SELECT * FROM {self.nombre}")
        return cursor.fetchall()

class Migracion:
    def __init__(self, version: int, modelo: Modelo):
        if not isinstance(version, int) or version <= 0:
            raise ValueError("La versión de la migración debe ser un número entero positivo")
        self.version = version
        self.modelo = modelo

    def aplicar(self, conexion: sqlite3.Connection):
        self.modelo.crear_tabla(conexion)

class AdministradorMigraciones:
    def __init__(self, conexion: sqlite3.Connection):
        if not conexion:
            raise ValueError("La conexión a la base de datos no puede ser vacía")
        self.conexion = conexion
        self.migraciones = []

    def agregar_migracion(self, migracion: Migracion):
        self.migraciones.append(migracion)

    def aplicar_migraciones(self):
        cursor = self.conexion.cursor()
        cursor.execute("CREATE TABLE IF NOT EXISTS migraciones (version INTEGER PRIMARY KEY)")
        self.conexion.commit()
        cursor.execute("SELECT version FROM migraciones ORDER BY version DESC LIMIT 1")
        ultima_version = cursor.fetchone()
        if ultima_version:
            ultima_version = ultima_version[0]
        else:
            ultima_version = 0
        for migracion in self.migraciones:
            if migracion.version > ultima_version:
                migracion.aplicar(self.conexion)
                cursor.execute("INSERT INTO migraciones (version) VALUES (?)", (migracion.version,))
                self.conexion.commit()

