                self.conexion.close()
            except sqlite3.Error as e:
                logging.error(f"Error al desconectar: {e}")
            finally:
                self.conexion = None

    def ejecutar_query(self, query):
        if self.conexion:
            try:
                cursor = self.conexion.cursor()
                cursor.execute(query)
                self.conexion.commit()
                return True
            except sqlite3.Error as e:
                logging.error(f"Error al ejecutar query: {e}")
                return False
        else:
            logging.error("No hay conexión")
            return False

    def health_check(self):
        if self.conexion:
            try:
                cursor = self.conexion.cursor()
                cursor.execute("SELECT 1")
                cursor.fetchone()
                return True
            except sqlite3.Error as e:
                logging.error(f"Error en health check: {e}")
                return False
        else:
            logging.error("No hay conexión")
            return False

class PoolConexiones:
    def __init__(self, db_name, max_conexiones):
        self.db_name = db_name
        self.max_conexiones = max_conexiones
        self.conexiones = []
        self.lock = threading.Lock()

    def obtener_conexion(self):
        with self.lock:
            for conexion in self.conexiones:
                if conexion.conexion and conexion.health_check():
                    return conexion
            if len(self.conexiones) < self.max_conexiones:
                nueva_conexion = Conexion(self.db_name)
                if nueva_conexion.conectar():
                    self.conexiones.append(nueva_conexion)
                    return nueva_conexion
            return None

    def devolver_conexion(self, conexion):
        with self.lock:
            if conexion in self.conexiones:
                self.conexiones.remove(conexion)
                conexion.desconectar()

    def health_check(self):
        with self.lock:
            for conexion in self.conexiones[:]:
                if not conexion.conexion or not conexion.health_check():
                    self.conexiones.remove(conexion)
                    conexion.desconectar()

def worker(pool):
    conexion = pool.obtener_conexion()
    if conexion:
        logging.info("Conexión obtenida")
        try:
            conexion.ejecutar_query("CREATE TABLE IF NOT EXISTS prueba (id INTEGER PRIMARY KEY)")
            conexion.ejecutar_query("INSERT INTO prueba (id) VALUES (1)")
        except Exception as e:
            logging.error(f"Error en worker: {e}")
        finally:
            pool.devolver_conexion(conexion)
    else:
        logging.error("No hay conexiones disponibles")

def main():
    db_name = "prueba.db"
    max_conexiones = 5
    pool = PoolConexiones(db_name, max_conexiones)
