import time
import random
import logging

# Configuración del circuit breaker
MAX_ATTEMPTS = 5
RESET_TIMEOUT = 30  # segundos

# Configuración del backoff exponencial
INITIAL_BACKOFF = 1  # segundo
MAX_BACKOFF = 30  # segundos

class CircuitBreaker:
    def __init__(self):
        self.attempts = 0
        self.last_failure = 0
        self.circuit_open = False

    def is_circuit_open(self):
        return self.circuit_open

    def reset(self):
        self.attempts = 0
        self.last_failure = 0
        self.circuit_open = False

    def try_execute(self, func):
        if not callable(func):
            raise ValueError("La función no es callable")

        if self.circuit_open:
            if time.time() - self.last_failure > RESET_TIMEOUT:
                self.reset()
            else:
                raise Exception("Circuit breaker abierto")

        try:
            result = func()
            if result is None:
                raise Exception("La función devolvió None")
            return result
        except Exception as e:
            self.attempts += 1
            self.last_failure = time.time()
            if self.attempts >= MAX_ATTEMPTS:
                self.circuit_open = True
            raise e

class Backoff:
    def __init__(self):
        self.backoff = INITIAL_BACKOFF

    def get_backoff(self):
        return self.backoff

    def increase_backoff(self):
        self.backoff = min(self.backoff * 2, MAX_BACKOFF)

    def reset(self):
        self.backoff = INITIAL_BACKOFF

def retry_with_circuit_breaker_and_backoff(func, max_retries=3):
    if not callable(func):
        raise ValueError("La función no es callable")

    if max_retries <= 0:
        raise ValueError("El número máximo de intentos debe ser mayor que cero")

    if RESET_TIMEOUT <= 0:
        raise ValueError("El tiempo de espera debe ser mayor que cero")

    if MAX_ATTEMPTS <= 0:
        raise ValueError("El número máximo de intentos debe ser mayor que cero")

    if INITIAL_BACKOFF <= 0:
        raise ValueError("El backoff inicial debe ser mayor que cero")

    circuit_breaker = CircuitBreaker()
    backoff = Backoff()

    for attempt in range(max_retries):
        try:
            return circuit_breaker.try_execute(func)
        except Exception as e:
            logging.error(f"Intento {attempt+1} fallido: {e}")
            backoff.increase_backoff()
            time.sleep(backoff.get_backoff() + random.uniform(0, 1))

            if circuit_breaker.is_circuit_open():
                logging.error("Circuit breaker abierto. Esperando...")
                time.sleep(RESET_TIMEOUT)
                circuit_breaker.reset()
                backoff.reset()

    raise Exception("Todos los intentos fallidos")

# Ejemplo de uso
def ejemplo_de_funcion():
    # Simulo una función que puede fallar
    import random
    if random.random() < 0.5:
        raise Exception("Error simulado")
    return "Función ejecutada con éxito"

try:
    resultado = retry_with_circuit_breaker_and_backoff(ejemplo_de_funcion)
    print(resultado)
except Exception as e:
    print(f"Error: {e}")
