class Modelo:
    def __init__(self, nombre: str):
        self.nombre = nombre
        self.campos = {}

    def agregar_campo(self, campo: Campo):
        self.campos[campo.nombre] = campo

class BaseDeDatos:
    def __init__(self, nombre: str):
        self.nombre = nombre
        try:
            self.conexion = sqlite3.connect(nombre)
            self.cursor = self.conexion.cursor()
        except sqlite3.Error as e:
            print(f"Error al conectar a la base de datos: {e}")

    def crear_tabla(self, modelo: Modelo):
        if not modelo.campos:
            print("El modelo no tiene campos")
            return

        campos = ", ".join([f"{campo.nombre} {campo.tipo}" for campo in modelo.campos.values()])
        self.cursor.execute(f"CREATE TABLE IF NOT EXISTS {modelo.nombre} (id INTEGER PRIMARY KEY, {campos})")
        self.conexion.commit()

    def insertar(self, modelo: Modelo, datos: Dict[str, str]):
        if not datos:
            print("No hay datos para insertar")
            return

        campos_modelo = list(modelo.campos.keys())
        if set(datos.keys()) != set(campos_modelo):
            print("Los campos en los datos no coinciden con los campos en el modelo")
            return

        campos = ", ".join(campos_modelo)
        valores = ", ".join(["?"] * len(datos))
        self.cursor.execute(f"INSERT INTO {modelo.nombre} ({campos}) VALUES ({valores})", list(datos.values()))
        self.conexion.commit()

    def seleccionar(self, modelo: Modelo, condiciones: Dict[str, str] = None):
        if not modelo.campos:
            print("El modelo no tiene campos")
            return

        if condiciones:
            condicion = " AND ".join([f"{campo} = '{valor}'" for campo, valor in condiciones.items()])
            self.cursor.execute(f"SELECT * FROM {modelo.nombre} WHERE {condicion}")
        else:
            self.cursor.execute(f"SELECT * FROM {modelo.nombre}")
        return self.cursor.fetchall()

    def verificar_tabla(self, modelo: Modelo):
        self.cursor.execute(f"SELECT name FROM sqlite_master WHERE type='table' AND name='{modelo.nombre}'")
        return self.cursor.fetchone() is not None

    def verificar_campo(self, modelo: Modelo, campo: str):
        self.cursor.execute(f"PRAGMA table_info({modelo.nombre})")
        campos = [c[1] for c in self.cursor.fetchall()]
        return campo in campos

class Migracion:
    def __init__(self, base_de_datos: BaseDeDatos):
        self.base_de_datos = base_de_datos

    def crear_tabla(self, modelo: Modelo):
        if self.base_de_datos.verificar_tabla(modelo):
            print(f"La tabla {modelo.nombre} ya existe")
            return

        self.base_de_datos.crear_tabla(modelo)

    def agregar_campo(self, modelo: Modelo, campo: Campo):
        if self.base_de_datos.verificar_campo(modelo, campo.nombre):
            print(f"El campo {campo.nombre} ya existe en la tabla {modelo.nombre}")
            return

        self.base_de_datos.cursor.execute(f"ALTER TABLE {modelo.nombre} ADD COLUMN {campo.nombre} {campo.tipo}")
        self.base_de_datos.conexion.commit()

    def eliminar_campo(self, modelo: Modelo, campo: str):
        if not self.base_de_datos.verificar_campo(modelo, campo):
            print(f"El campo {campo} no existe en la tabla {modelo.nombre}")
            return

        self.base_de_datos.cursor.execute(f"ALTER TABLE {modelo.nombre} DROP COLUMN {campo}")
        self.base_de_datos.conexion.commit()

