from collections import defaultdict, deque

class Tarea:
    def __init__(self, nombre):
        self.nombre = nombre
        self.dependencias = set()
        self.dependientes = set()

class Planificador:
    def __init__(self):
        self.tareas = {}
        self.grafo = defaultdict(list)

    def agregar_tarea(self, nombre):
        if not nombre:
            raise ValueError("El nombre de la tarea no puede ser vacío")
        if nombre in self.tareas:
            raise ValueError("La tarea ya existe")
        self.tareas[nombre] = Tarea(nombre)

    def agregar_dependencia(self, nombre_tarea, nombre_dependencia):
        if not nombre_tarea or not nombre_dependencia:
            raise ValueError("Los nombres de las tareas no pueden ser vacíos")
        if nombre_tarea not in self.tareas:
            self.agregar_tarea(nombre_tarea)
        if nombre_dependencia not in self.tareas:
            self.agregar_tarea(nombre_dependencia)
        if nombre_dependencia in self.tareas[nombre_tarea].dependencias:
            raise ValueError("La dependencia ya existe")
        if nombre_tarea in self.tareas[nombre_dependencia].dependientes:
            raise ValueError("Se detectó un ciclo en el grafo")
        self.tareas[nombre_tarea].dependencias.add(nombre_dependencia)
        self.tareas[nombre_dependencia].dependientes.add(nombre_tarea)
        self.grafo[nombre_dependencia].append(nombre_tarea)

    def planificar(self):
        cola = deque([tarea for tarea in self.tareas if not self.tareas[tarea].dependencias])
        tareas_planificadas = []
        while cola:
            nombre_tarea = cola.popleft()
            tareas_planificadas.append(nombre_tarea)
            for tarea_dependiente in self.grafo[nombre_tarea]:
                self.tareas[tarea_dependiente].dependencias.remove(nombre_tarea)
                if not self.tareas[tarea_dependiente].dependencias:
                    cola.append(tarea_dependiente)
        if len(tareas_planificadas) != len(self.tareas):
            raise ValueError("Se detectó un ciclo en el grafo")
        return tareas_planificadas

    def imprimir_planificacion(self):
        try:
            tareas_planificadas = self.planificar()
            print("Orden de ejecución de tareas:")
            for tarea in tareas_planificadas:
                print(tarea)
        except ValueError as e:
            print(f"Error: {e}")

# Ejemplo de uso
planificador = Planificador()
planificador.agregar_tarea("a")
planificador.agregar_tarea("b")
planificador.agregar_tarea("c")
planificador.agregar_tarea("d")
planificador.agregar_dependencia("b", "a")
planificador.agregar_dependencia("c", "a")
planificador.agregar_dependencia("d", "b")
planificador.agregar_dependencia("d", "c")
planificador.imprimir_planificacion()
