import json

class Archivo:
    def __init__(self, nombre, contenido):
        if not nombre:
            raise ValueError("El nombre del archivo no puede ser vacío")
        if not contenido:
            raise ValueError("El contenido del archivo no puede ser vacío")
        self.nombre = nombre
        self.contenido = contenido

class Commit:
    def __init__(self, archivos, mensaje, timestamp=None):
        if not mensaje:
            raise ValueError("El mensaje del commit no puede ser vacío")
        if not archivos:
            raise ValueError("La lista de archivos no puede ser vacía")
        if timestamp is not None and timestamp < 0:
            raise ValueError("El timestamp no puede ser negativo")
        self.archivos = archivos
        self.mensaje = mensaje
        self.timestamp = timestamp if timestamp else time.time()

    def calcular_hash(self):
        hash_archivos = {}
        for archivo in self.archivos:
            hash_archivos[archivo.nombre] = hashlib.sha256(archivo.contenido.encode()).hexdigest()
        return hashlib.sha256(json.dumps(hash_archivos, sort_keys=True).encode()).hexdigest()

class Repositorio:
    def __init__(self, ruta):
        self.ruta = ruta
        self.commits = []
        self.archivos = {}

    def agregar_archivo(self, archivo):
        self.archivos[archivo.nombre] = archivo

    def hacer_commit(self, mensaje, archivos):
        commit = Commit(archivos, mensaje)
        self.commits.append(commit)
        return commit

    def obtener_commits(self, pagina=1, cantidad=10):
        inicio = (pagina - 1) * cantidad
        fin = inicio + cantidad
        return self.commits[inicio:fin]

    def obtener_commit(self, indice):
        if indice < 0 or indice >= len(self.commits):
            return None
        return self.commits[indice]

    def obtener_archivos(self, commit):
        if commit is None:
            return []
        return commit.archivos

