def calculate_frequencies(text):
    """Calcula la frecuencia de cada caracter en el texto."""
    if not text:
        return {}
    frequencies = defaultdict(int)
    for character in text:
        frequencies[character] += 1
    return frequencies

def build_tree(frequencies):
    """Construye el árbol de Huffman a partir de las frecuencias."""
    if not frequencies:
        return None
    nodes = [Node(character, frequency) for character, frequency in frequencies.items()]
    heapq.heapify(nodes)
    while len(nodes) > 1:
        node1 = heapq.heappop(nodes)
        node2 = heapq.heappop(nodes)
        parent_node = Node(None, node1.frequency + node2.frequency)
        parent_node.left = node1
        parent_node.right = node2
        heapq.heappush(nodes, parent_node)
    return nodes[0]

def generate_codes(node, code, codes):
    """Genera los códigos Huffman para cada caracter."""
    if node.character is not None:
        codes[node.character] = code
    if node.left is not None:
        generate_codes(node.left, code + "0", codes)
    if node.right is not None:
        generate_codes(node.right, code + "1", codes)

def compress(text):
    """Comprime el texto utilizando la codificación Huffman."""
    if not text:
        return "", {}
    frequencies = calculate_frequencies(text)
    tree = build_tree(frequencies)
    codes = {}
    generate_codes(tree, "", codes)
    compressed_text = ""
    for character in text:
        compressed_text += codes[character]
    return compressed_text, codes

def decompress(compressed_text, codes):
    """Descomprime el texto utilizando la codificación Huffman."""
    if not compressed_text or not codes:
        return ""
    reverse_codes = {code: character for character, code in codes.items()}
    decompressed_text = ""
    code = ""
    for bit in compressed_text:
        code += bit
        if code in reverse_codes:
            decompressed_text += reverse_codes[code]
            code = ""
    return decompressed_text

# Ejemplo de uso
text = "Este es un ejemplo de texto para comprimir"
compressed_text, codes = compress(text)
print("Texto comprimido:", compressed_text)
print("Códigos Huffman:", codes)
decompressed_text = decompress(compressed_text, codes)
print("Texto descomprimido:", decompressed_text)
