import re

class RegexParser:
    def __init__(self, regex):
        self.regex = regex
        self.pos = 0

    def parse(self):
        if not self.regex:
            return None
        return self.parse_expression()

    def parse_expression(self):
        expr = self.parse_term()
        while self.pos < len(self.regex) and self.regex[self.pos] in ['|']:
            if self.regex[self.pos] == '|':
                self.pos += 1
                expr2 = self.parse_term()
                expr = (expr, expr2)
        return expr

    def parse_term(self):
        factor = self.parse_factor()
        while self.pos < len(self.regex) and self.regex[self.pos] in ['*', '+', '?']:
            if self.regex[self.pos] == '*':
                self.pos += 1
                factor = (factor, '*')
            elif self.regex[self.pos] == '+':
                self.pos += 1
                factor = (factor, '+')
            elif self.regex[self.pos] == '?':
                self.pos += 1
                factor = (factor, '?')
        return factor

    def parse_factor(self):
        if self.pos >= len(self.regex):
            raise Exception("Fin de la expresión regular")
        if self.regex[self.pos] == '(':
            self.pos += 1
            expr = self.parse_expression()
            if self.pos >= len(self.regex) or self.regex[self.pos] != ')':
                raise Exception("Paréntesis no balanceados")
            self.pos += 1
            return expr
        elif self.regex[self.pos] == '[':
            self.pos += 1
            clase = self.parse_clase()
            if self.pos >= len(self.regex) or self.regex[self.pos] != ']':
                raise Exception("Corchetes no balanceados")
            self.pos += 1
            return clase
        else:
            if not self.regex[self.pos].isalnum() and self.regex[self.pos] not in ['*', '+', '?', '(', ')', '[', ']']:
                raise Exception("Carácter no válido en la expresión regular")
            literal = self.regex[self.pos]
            self.pos += 1
            return literal

    def parse_clase(self):
        clase = ''
        while self.pos < len(self.regex) and self.regex[self.pos] != ']':
            if self.regex[self.pos] == '\\':
                self.pos += 1
                if self.pos >= len(self.regex):
                    raise Exception("Fin de la expresión regular")
                clase += self.regex[self.pos]
                self.pos += 1
            else:
                clase += self.regex[self.pos]
                self.pos += 1
        return clase

