import networkx as nx
import threading
from typing import Callable, Dict, List
import logging

# Configuración de logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

class Task:
    """Representa una tarea con un nombre y una función asociada."""
    def __init__(self, name: str, func: Callable):
        self.name = name
        self.func = func

class Scheduler:
    """Maneja el grafo de dependencias y ejecuta las tareas."""
    def __init__(self):
        self.graph = nx.DiGraph()
        self.tasks: Dict[str, Task] = {}

    def add_task(self, name: str, func: Callable):
        """Agrega una tarea al grafo y al diccionario de tareas."""
        if name in self.tasks:
            logger.warning(f"La tarea '{name}' ya existe.")
            return
        self.tasks[name] = Task(name, func)
        self.graph.add_node(name)

    def add_dependency(self, task1: str, task2: str):
        """Agrega una dependencia entre dos tareas en el grafo."""
        if not self.graph.has_node(task1) or not self.graph.has_node(task2):
            logger.warning(f"Una de las tareas no existe.")
            return
        if self.graph.has_edge(task1, task2):
            logger.warning(f"La dependencia entre '{task1}' y '{task2}' ya existe.")
            return
        self.graph.add_edge(task1, task2)

    def schedule(self):
        """Verifica si el grafo tiene ciclos y ejecuta las tareas en orden topológico."""
        if not self.graph:
            logger.warning("El grafo está vacío.")
            return
        try:
            order = list(nx.topological_sort(self.graph))
        except nx.NetworkXUnfeasible:
            logger.error("El grafo tiene ciclos.")
            return
        for task_name in order:
            task = self.tasks[task_name]
            if not task.func:
                logger.error(f"La tarea '{task_name}' no tiene una función asociada.")
                continue
            try:
                threading.Thread(target=task.func).start()
            except Exception as e:
                logger.error(f"Error al ejecutar la tarea '{task_name}': {e}")

# Ejemplo de uso
def tarea1():
    logger.info("Tarea 1")

def tarea2():
    logger.info("Tarea 2")

def tarea3():
    logger.info("Tarea 3")

scheduler = Scheduler()
scheduler.add_task("tarea1", tarea1)
scheduler.add_task("tarea2", tarea2)
scheduler.add_task("tarea3", tarea3)
scheduler.add_dependency("tarea1", "tarea2")
scheduler.add_dependency("tarea2", "tarea3")
scheduler.schedule()
