import enum

class TokenType(enum.Enum):
    LITERAL = 1
    DOT = 2
    STAR = 3
    PLUS = 4
    QUESTION = 5
    LPAREN = 6
    RPAREN = 7
    VBAR = 8
    EOF = 9

class Token:
    def __init__(self, type, value):
        self.type = type
        self.value = value

    def __repr__(self):
        return f'Token({self.type}, {self.value})'

class Lexer:
    def __init__(self, pattern):
        self.pattern = pattern
        self.pos = 0

    def get_token(self):
        if self.pos >= len(self.pattern):
            return Token(TokenType.EOF, None)

        if self.pattern[self.pos] == '.':
            self.pos += 1
            return Token(TokenType.DOT, '.')
        elif self.pattern[self.pos] == '*':
            self.pos += 1
            return Token(TokenType.STAR, '*')
        elif self.pattern[self.pos] == '+':
            self.pos += 1
            return Token(TokenType.PLUS, '+')
        elif self.pattern[self.pos] == '?':
            self.pos += 1
            return Token(TokenType.QUESTION, '?')
        elif self.pattern[self.pos] == '(':
            self.pos += 1
            return Token(TokenType.LPAREN, '(')
        elif self.pattern[self.pos] == ')':
            self.pos += 1
            return Token(TokenType.RPAREN, ')')
        elif self.pattern[self.pos] == '|':
            self.pos += 1
            return Token(TokenType.VBAR, '|')
        else:
            literal = self.pattern[self.pos]
            self.pos += 1
            return Token(TokenType.LITERAL, literal)

class Parser:
    def __init__(self, lexer):
        self.lexer = lexer
        self.token = self.lexer.get_token()

    def parse(self):
        return self.parse_expression()

    def parse_expression(self):
        result = self.parse_term()
        while self.token.type == TokenType.VBAR:
            self.token = self.lexer.get_token()
            result = ('|', result, self.parse_term())
        return result

    def parse_term(self):
        result = self.parse_factor()
        while self.token.type in (TokenType.STAR, TokenType.PLUS, TokenType.QUESTION):
            if self.token.type == TokenType.STAR:
                self.token = self.lexer.get_token()
                result = ('*', result)
            elif self.token.type == TokenType.PLUS:
                self.token = self.lexer.get_token()
                result = ('+', result)
            elif self.token.type == TokenType.QUESTION:
                self.token = self.lexer.get_token()
                result = ('?', result)
        return result

    def parse_factor(self):
        if self.token.type == TokenType.LITERAL:
            result = self.token.value
            self.token = self.lexer.get_token()
            return result
        elif self.token.type == TokenType.DOT:
            self.token = self.lexer.get_token()
            return '.'
        elif self.token.type == TokenType.LPAREN:
            self.token = self.lexer.get_token()
            result = self.parse_expression()
            if self.token.type != TokenType.RPAREN:
                raise Exception('Expected )')
            self.token = self.lexer.get_token()
            return result
        elif self.token.type == TokenType.EOF:
            raise Exception('Unexpected end of pattern')

class Matcher:
    def __init__(self, pattern):
        self.pattern = pattern

    def match(self, string):
        if not string:
            return False
        parser = Parser(Lexer(self.pattern))
        parsed_pattern = parser.parse()
        return self.match_parsed(string, parsed_pattern)

    def match_parsed(self, string, parsed_pattern):
        if isinstance(parsed_pattern, str):
            if len(string) != 1 or string[0] != parsed_pattern:
                return False
            return True
        elif len(parsed_pattern) == 2: # *
            if parsed_pattern[0] == '*':
                return self.match_parsed(string, parsed_pattern[1])
            elif parsed_pattern[0] == '+':
                if not string:
                    return False
                return self.match_parsed(string[1:], parsed_pattern[1])
            elif parsed_pattern[0] == '?':
                return self.match_parsed(string, parsed_pattern[1]) or (string and self.match_parsed(string[1:], parsed_pattern[1]))
        elif len(parsed_pattern) == 3: # |
            return self.match_parsed(string, parsed_pattern[1]) or self.match_parsed(string, parsed_pattern[2])
        else:
            raise Exception('Invalid parsed pattern')

# Ejemplo de uso
matcher = Matcher('a*b')
print(matcher.match('aaab')) # True

