            elif modifier == '+':
                expr = self.parse_one_or_more(expr)
            elif modifier == '?':
                expr = self.parse_zero_or_one(expr)
        if self.pos < len(self.pattern) and self.pattern[self.pos] == '|':
            self.pos += 1
            expr2 = self.parse_expression()
            return f'({expr}|{expr2})'
        return expr

    def parse_term(self):
        if self.pos < len(self.pattern) and self.pattern[self.pos] == '(':
            self.pos += 1
            expr = self.parse_expression()
            self.pos += 1  # cerrar paréntesis
            return expr
        elif self.pos < len(self.pattern) and self.pattern[self.pos] == '[':
            self.pos += 1
            chars = self.parse_char_set()
            self.pos += 1  # cerrar corchete
            return chars
        elif self.pos < len(self.pattern) and self.pattern[self.pos] == '.':
            self.pos += 1
            return '.'
        elif self.pos < len(self.pattern) and self.pattern[self.pos] == '^':
            self.pos += 1
            return '^'
        elif self.pos < len(self.pattern) and self.pattern[self.pos] == '$':
            self.pos += 1
            return '$'
        else:
            if self.pos < len(self.pattern):
                char = self.pattern[self.pos]
                self.pos += 1
                return char
            else:
                return ''

    def parse_zero_or_more(self, expr):
        if expr == '':
            return ''
        return f'({expr})*'

    def parse_one_or_more(self, expr):
        if expr == '':
            return ''
        return f'({expr})+'

    def parse_zero_or_one(self, expr):
        if expr == '':
            return ''
        return f'({expr})?'

    def parse_char_set(self):
        chars = ''
        while self.pos < len(self.pattern) and self.pattern[self.pos] != ']':
            chars += self.pattern[self.pos]
            self.pos += 1
        if chars == '':
            return ''
        return f'[{chars}]'

def compile_regex(pattern):
    parser = RegexParser(pattern)
    return parser.parse()

def match_regex(pattern, string):
    if not string:
        return False
    compiled_pattern = compile_regex(pattern)
    return re.fullmatch(compiled_pattern, string) is not None

