import threading
import time
import random
import logging

# Configuración de logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(threadName)s - %(levelname)s - %(message)s')

class Conexion:
    def __init__(self, id):
        self.id = id
        self.esta_viva = True

    def health_check(self):
        # Simulación de health-check
        resultado = random.choice([True, False])
        if not resultado:
            self.esta_viva = False
        return resultado

class PoolDeConexiones:
    def __init__(self, tamano_pool):
        if tamano_pool <= 0:
            raise ValueError("El tamaño del pool debe ser mayor que 0")
        self.tamano_pool = tamano_pool
        self.conexiones = [Conexion(i) for i in range(tamano_pool)]
        self.candado = threading.Lock()
        self.id_conexion = tamano_pool  # ID único y consecutivo para nuevas conexiones

    def obtener_conexion(self):
        with self.candado:
            for conexion in self.conexiones:
                if conexion.esta_viva:
                    return conexion
            return None

    def reemplazar_conexion(self, conexion):
        with self.candado:
            try:
                self.conexiones.remove(conexion)
                nueva_conexion = Conexion(self.id_conexion)
                self.conexiones.append(nueva_conexion)
                self.id_conexion += 1  # Incrementar ID para la próxima conexión
                return nueva_conexion
            except Exception as e:
                logging.error(f"Error al reemplazar conexión: {e}")
                return None

    def health_check_periodico(self):
        while True:
            for conexion in self.conexiones:
                if not conexion.health_check():
                    logging.warning(f'Conexión {conexion.id} fallida. Reemplazándola...')
