import enum

class TokenType(enum.Enum):
    LITERAL = 1
    DOT = 2
    STAR = 3
    PLUS = 4
    QUESTION = 5
    LPAREN = 6
    RPAREN = 7
    VBAR = 8
    EOF = 9

class Token:
    def __init__(self, type, value):
        self.type = type
        self.value = value

    def __repr__(self):
        return f'Token({self.type}, {self.value})'

class Lexer:
    def __init__(self, text):
        self.text = text
        self.pos = 0
        self.current_char = self.text[self.pos] if self.text else None

    def error(self):
        raise Exception('Carácter inválido')

    def advance(self):
        self.pos += 1
        if self.pos > len(self.text) - 1:
            self.current_char = None
        else:
            self.current_char = self.text[self.pos]

    def skip_whitespace(self):
        while self.current_char is not None and self.current_char.isspace():
            self.advance()

    def integer(self):
        result = ''
        while self.current_char is not None and self.current_char.isdigit():
            result += self.current_char
            self.advance()
        return int(result)

    def literal(self):
        result = self.current_char
        self.advance()
        return result

    def get_next_token(self):
        while self.current_char is not None:
            if self.current_char.isspace():
                self.skip_whitespace()
                continue

            if self.current_char.isalpha() or self.current_char.isdigit():
                return Token(TokenType.LITERAL, self.literal())

            if self.current_char == '.':
                self.advance()
                return Token(TokenType.DOT, '.')

            if self.current_char == '*':
                self.advance()
                return Token(TokenType.STAR, '*')

            if self.current_char == '+':
                self.advance()
                return Token(TokenType.PLUS, '+')

            if self.current_char == '?':
                self.advance()
                return Token(TokenType.QUESTION, '?')

            if self.current_char == '(':
                self.advance()
                return Token(TokenType.LPAREN, '(')

            if self.current_char == ')':
                self.advance()
                return Token(TokenType.RPAREN, ')')

            if self.current_char == '|':
                self.advance()
                return Token(TokenType.VBAR, '|')

            self.error()

        return Token(TokenType.EOF, None)

class Parser:
    def __init__(self, lexer):
        self.lexer = lexer
        self.current_token = self.lexer.get_next_token()

    def error(self):
        raise Exception('Sintaxis inválida')

    def eat(self, token_type):
        if self.current_token.type == token_type:
            self.current_token = self.lexer.get_next_token()
        else:
            self.error()

    def factor(self):
        token = self.current_token
        if token.type == TokenType.LITERAL:
            self.eat(TokenType.LITERAL)
            return token.value
        elif token.type == TokenType.LPAREN:
            self.eat(TokenType.LPAREN)
            node = self.expr()
            self.eat(TokenType.RPAREN)
            return node
        elif token.type == TokenType.DOT:
            self.eat(TokenType.DOT)
            return '.'
        else:
            self.error()

    def term(self):
        node = self.factor()
        while self.current_token.type in (TokenType.STAR, TokenType.PLUS, TokenType.QUESTION):
            token = self.current_token
            if token.type == TokenType.STAR:
                self.eat(TokenType.STAR)
                node = {'type': 'star', 'value': node}
            elif token.type == TokenType.PLUS:
                self.eat(TokenType.PLUS)
                node = {'type': 'plus', 'value': node}
            elif token.type == TokenType.QUESTION:
                self.eat(TokenType.QUESTION)
                node = {'type': 'question', 'value': node}
        return node

    def expr(self):
        node = self.term()
        while self.current_token.type == TokenType.VBAR:
            token = self.current_token
            self.eat(TokenType.VBAR)
            node = {'type': 'vbar', 'left': node, 'right': self.term()}
        return node

def parse(text):
    lexer = Lexer(text)
    parser = Parser(lexer)
    return parser.expr()

# Ejemplo de uso
text = "a*b|c?"
ast = parse(text)
print(ast)
