class RegexParser:
    def __init__(self, pattern):
        self.pattern = pattern
        self.pos = 0

    def parse(self):
        if not self.pattern:
            raise ValueError("Patrón vacío")
        return self.parse_expression()

    def parse_expression(self):
        expr = self.parse_term()
        while self.pos < len(self.pattern) and self.pattern[self.pos] == '|':
            self.pos += 1
            if self.pos >= len(self.pattern):
                raise ValueError("Patrón inválido: '|' al final")
            expr2 = self.parse_term()
            expr = (expr, '|', expr2)
        return expr

    def parse_term(self):
        term = self.parse_factor()
        while self.pos < len(self.pattern) and self.pattern[self.pos] in ['*', '+', '?']:
            quantifier = self.pattern[self.pos]
            self.pos += 1
            if self.pos >= len(self.pattern):
                raise ValueError("Patrón inválido: cuantificador al final")
            term = (term, quantifier)
        return term

    def parse_factor(self):
        if self.pos >= len(self.pattern):
            raise ValueError("Patrón inválido: factor esperado")
        if self.pattern[self.pos] == '.':
            self.pos += 1
            return '.'
        elif self.pattern[self.pos] == '[':
            self.pos += 1
            chars = []
            while self.pos < len(self.pattern) and self.pattern[self.pos] != ']':
                chars.append(self.pattern[self.pos])
                self.pos += 1
            if self.pos >= len(self.pattern) or self.pattern[self.pos] != ']':
                raise ValueError("Patrón inválido: '[' sin cierre")
            self.pos += 1
            return '[' + ''.join(chars) + ']'
        elif self.pattern[self.pos] == '^':
            self.pos += 1
            return '^'
        elif self.pattern[self.pos] == '$':
            self.pos += 1
            return '$'
        else:
            char = self.pattern[self.pos]
            self.pos += 1
            return char

    def match(self, string):
        return self.match_expression(self.parse(), string)

    def match_expression(self, expr, string):
        if isinstance(expr, tuple):
            if expr[1] == '|':
                return self.match_expression(expr[0], string) or self.match_expression(expr[2], string)
            elif expr[1] == '*':
                return self.match_star(expr[0], string)
            elif expr[1] == '+':
                return self.match_plus(expr[0], string)
            elif expr[1] == '?':
                return self.match_question(expr[0], string)
        else:
            return self.match_factor(expr, string)

    def match_star(self, expr, string):
        if not string:
            return True
        return self.match_expression(expr, string) or self.match_star(expr, string[1:])

    def match_plus(self, expr, string):
        if not string:
            return False
        return self.match_expression(expr, string) and (self.match_plus(expr, string[1:]) or not string[1:])

    def match_question(self, expr, string):
        return self.match_expression(expr, string) or not string

    def match_factor(self, factor, string):
        if factor == '.':
            return bool(string)
        elif factor == '^':
            return not string or self.match_factor(string[0], string[1:])
        elif factor == '$':
            return not string
        elif isinstance(factor, str) and len(factor) == 1:
            return bool(string) and factor == string[0]
        elif isinstance(factor, str) and factor.startswith('[') and factor.endswith(']'):
            return bool(string) and string[0] in factor[1:-1]
        else:
            raise ValueError("Factor inválido")

