import logging
import queue
import threading
import time
import random

class Connection:
    def __init__(self, name):
        self.name = name
        self.connected = False

    def connect(self):
        if not self.connected:
            self.connected = True
            logging.info(f"Connection {self.name} established")

    def disconnect(self):
        if self.connected:
            self.connected = False
            logging.info(f"Connection {self.name} closed")

    def health_check(self):
        # Simulación de health-check
        return random.choice([True, False])

class ConnectionPool:
    def __init__(self, pool_size, health_check_interval):
        if pool_size <= 0:
            raise ValueError("Pool size must be greater than 0")
        if health_check_interval <= 0:
            raise ValueError("Health check interval must be greater than 0")

        self.pool_size = pool_size
        self.health_check_interval = health_check_interval
        self.connections = []
        self.connection_queue = queue.Queue()
        self.closed = False
        self.lock = threading.Lock()

        for i in range(pool_size):
            connection = Connection(f"Connection {i+1}")
            self.connections.append(connection)
            self.connection_queue.put(connection)

        self.health_check_thread = threading.Thread(target=self.periodic_health_check)
        self.health_check_thread.start()

    def get_connection(self):
        if self.closed:
            raise Exception("Connection pool is closed")

        with self.lock:
            if not self.connection_queue.empty():
                connection = self.connection_queue.get()
                if not connection.connected:
                    connection.connect()
                return connection
            else:
                raise Exception("No connections available in the pool")

    def return_connection(self, connection):
        if self.closed:
            raise Exception("Connection pool is closed")

        with self.lock:
            if not any(c is connection for c in list(self.connection_queue.queue)):
                self.connection_queue.put(connection)

    def periodic_health_check(self):
        while not self.closed:
            with self.lock:
                for connection in self.connections:
                    if not connection.health_check():
                        logging.warning(f"Connection {connection.name} did not respond to health check")
                        if connection.connected:
                            connection.disconnect()
                    else:
                        logging.info(f"Connection {connection.name} responded to health check")
            time.sleep(self.health_check_interval)

    def close(self):
        self.closed = True
        self.health_check_thread.join()
        with self.lock:
            for connection in self.connections:
                if connection.connected:
                    connection.disconnect()

# Ejemplo de uso
if __name__ == "__main__":
    logging.basicConfig(level=logging.INFO)
    pool = ConnectionPool(5, 5)  # Pool de 5 conexiones con health-check cada 5 segundos
    try:
        connection = pool.get_connection()
        logging.info(f"Obtained connection {connection.name}")
        # Simulación de uso de la conexión
        time.sleep(2)
        pool.return_connection(connection)
    except Exception as e:
        logging.error(f"Error: {e}")
    finally:
        pool.close()
