logging.basicConfig(level=logging.INFO)

class Conexion:
    def __init__(self, host, database, user, password):
        self.host = host
        self.database = database
        self.user = user
        self.password = password
        self.conexion = None

    def conectar(self):
        try:
            self.conexion = psycopg2.connect(
                host=self.host,
                database=self.database,
                user=self.user,
                password=self.password
            )
            return True
        except psycopg2.Error as e:
            logging.error(f"Error al conectar: {e}")
            return False

    def desconectar(self):
        if self.conexion:
            self.conexion.close()
            self.conexion = None

    def health_check(self):
        if not self.conexion:
            return False
        try:
            cursor = self.conexion.cursor()
            cursor.execute("SELECT 1")
            cursor.fetchone()
            return True
        except psycopg2.Error as e:
            logging.error(f"Error en health-check: {e}")
            return False

class PoolDeConexiones:
    def __init__(self, host, database, user, password, max_conexiones):
        self.host = host
        self.database = database
        self.user = user
        self.password = password
        self.max_conexiones = max_conexiones
        self.conexiones = []
        self.lock = threading.Lock()

    def obtener_conexion(self):
        with self.lock:
            for conexion in self.conexiones:
                if conexion.conexion and conexion.health_check():
                    return conexion
            if len(self.conexiones) < self.max_conexiones:
                nueva_conexion = Conexion(self.host, self.database, self.user, self.password)
                if nueva_conexion.conectar():
                    self.conexiones.append(nueva_conexion)
                    return nueva_conexion
                else:
                    logging.error("Error al conectar a la base de datos")
            return None

    def devolver_conexion(self, conexion):
        with self.lock:
            if conexion in self.conexiones:
                self.conexiones.remove(conexion)
                conexion.desconectar()
            else:
                logging.error("Conexión no encontrada en el pool")

    def iniciar_health_check(self):
        def health_check_periodico():
            while True:
                with self.lock:
                    for conexion in self.conexiones[:]:
                        if not conexion.health_check():
                            self.conexiones.remove(conexion)
                            conexion.desconectar()
                time.sleep(60)  # health-check cada 1 minuto
        try:
            threading.Thread(target=health_check_periodico, daemon=True).start()
        except Exception as e:
            logging.error(f"Error al iniciar el hilo de health-check: {e}")

