from collections import defaultdict, deque

class Scheduler:
    def __init__(self):
        self.graph = defaultdict(list)
        self.in_degree = defaultdict(int)
        self.tasks = set()

    def add_task(self, task, dependencies=None):
        if dependencies is None:
            dependencies = []
        if task in self.tasks:
            raise ValueError("Tarea ya existente")
        self.tasks.add(task)
        for dependency in dependencies:
            if dependency not in self.tasks:
                raise ValueError("Dependencia no existente")
            self.graph[dependency].append(task)
            self.in_degree[task] += 1
        if task not in self.in_degree:
            self.in_degree[task] = 0

    def schedule(self):
        queue = deque([task for task, degree in self.in_degree.items() if degree == 0])
        scheduled_tasks = []
        while queue:
            task = queue.popleft()
            scheduled_tasks.append(task)
            for neighbor in self.graph[task]:
                self.in_degree[neighbor] -= 1
                if self.in_degree[neighbor] == 0:
                    queue.append(neighbor)
        if len(scheduled_tasks) != len(self.in_degree):
            cycle_tasks = [task for task, degree in self.in_degree.items() if degree != 0]
            raise ValueError(f"Ciclo detectado en el grafo: {cycle_tasks}")
        return scheduled_tasks

    def add_edge(self, task1, task2):
        if task1 not in self.tasks:
            raise ValueError("Tarea no existente")
        if task2 not in self.tasks:
            raise ValueError("Tarea no existente")
        if task1 == task2:
            raise ValueError("Dependencia circular")
        self.graph[task1].append(task2)
        self.in_degree[task2] += 1

    def remove_task(self, task):
        if task not in self.tasks:
            raise ValueError("Tarea no existente")
        self.tasks.remove(task)
        del self.in_degree[task]
        for dependencies in self.graph.values():
            if task in dependencies:
                dependencies.remove(task)

def main():
    scheduler = Scheduler()
    scheduler.add_task('A')
    scheduler.add_task('B', ['A'])
    scheduler.add_task('C', ['A'])
    scheduler.add_task('D', ['B', 'C'])
    print(scheduler.schedule())

if __name__ == "__main__":
    main()
