from typing import Callable, Any
from collections import defaultdict

class PubSub:
    def __init__(self):
        self.subscribers = defaultdict(list)

    def subscribe(self, topic: str, predicate: Callable[[Any], bool] = None) -> Callable:
        """Subscribe a function to a topic with an optional predicate filter."""
        def decorator(func: Callable[[Any], None]) -> Callable:
            """Decorator to subscribe a function to a topic."""
            self.subscribers[topic].append((func, predicate))
            return func
        return decorator

    def publish(self, topic: str, message: Any) -> None:
        """Publish a message to a topic."""
        if message is None:
            raise ValueError("Message cannot be None")

        if topic not in self.subscribers:
            # No subscribers for this topic, do nothing
            return

        for func, predicate in self.subscribers[topic]:
            if predicate is None or predicate(message):
                func(message)

    def unsubscribe(self, topic: str, func: Callable[[Any], None]) -> None:
        """Unsubscribe a function from a topic."""
        if topic not in self.subscribers:
            # Topic does not exist, do nothing
            return

        self.subscribers[topic] = [(f, p) for f, p in self.subscribers[topic] if f != func]

def main() -> None:
    pubsub = PubSub()

    @pubsub.subscribe('topic1')
    def handle_topic1(message: Any) -> None:
        print(f'Tópico 1: {message}')

    @pubsub.subscribe('topic1', lambda x: x > 5)
    def handle_topic1_filtered(message: Any) -> None:
        print(f'Tópico 1 filtrado: {message}')

    @pubsub.subscribe('topic2')
    def handle_topic2(message: Any) -> None:
        print(f'Tópico 2: {message}')

    pubsub.publish('topic1', 'Hola')
    pubsub.publish('topic1', 10)
    pubsub.publish('topic2', 'Mundo')
    pubsub.unsubscribe('topic1', handle_topic1)
    pubsub.publish('topic1', 'Después de unsubscribe')

