        self.migraciones.append(migracion)
        self.migraciones.sort(key=lambda m: m.version)

    def aplicar_migraciones(self):
        cursor = self.conexion.cursor()
        cursor.execute("CREATE TABLE IF NOT EXISTS migraciones (version INTEGER PRIMARY KEY)")
        cursor.execute("SELECT version FROM migraciones ORDER BY version DESC LIMIT 1")
        fila = cursor.fetchone()
        if fila is None:
            self.ultima_version = 0
        else:
            self.ultima_version = fila[0]
        for migracion in self.migraciones:
            if migracion.version > self.ultima_version:
                migracion.aplicar(self.conexion)
                cursor.execute("INSERT INTO migraciones (version) VALUES (?)", (migracion.version,))
                self.conexion.commit()
                self.ultima_version = migracion.version

