        campos = ", ".join(datos.keys())
        valores = ", ".join("?" for _ in datos)
        cursor.execute(f"INSERT INTO {modelo_nombre} ({campos}) VALUES ({valores})", list(datos.values()))
        self.conexion.commit()

    def obtener(self, modelo_nombre: str, id: int):
        if modelo_nombre not in self.modelos:
