            self.conexion = None

    def health_check(self):
        try:
            cursor = self.conexion.cursor()
            cursor.execute("SELECT 1")
            cursor.fetchone()
            return True
        except psycopg2.Error as e:
            logger.error(f"Error en health-check: {e}")
            return False


class PoolConexiones:
    def __init__(self, num_conexiones, host, database, user, password):
        if num_conexiones <= 0:
            raise ValueError("El número de conexiones debe ser mayor que cero")

        self.num_conexiones = num_conexiones
        self.host = host
        self.database = database
        self.user = user
        self.password = password
        self.conexiones = queue.Queue()
        self.lock = threading.Lock()
        self.thread_health_check = None

        for _ in range(num_conexiones):
            conexion = Conexion(host, database, user, password)
            if conexion.conectar():
                self.conexiones.put(conexion)
            else:
