    def add_dependency(self, task1: str, task2: str):
        if task1 not in self.tasks or task2 not in self.tasks:
            raise ValueError(f"Una o ambas tareas no existen: '{task1}', '{task2}'")
        if self.graph.has_edge(task2, task1):
            raise ValueError(f"Dependencia cíclica detectada entre '{task1}' y '{task2}'")
        self.graph.add_edge(task1, task2)

    def schedule(self):
        if not self.tasks:
            print("No hay tareas para ejecutar")
            return

        try:
            order = list(nx.topological_sort(self.graph))
        except nx.NetworkXUnfeasible:
            raise ValueError("El grafo tiene un ciclo y no se puede ordenar topológicamente")

        threads: List[threading.Thread] = []
        for task_name in order:
            task = self.tasks[task_name]
            thread = threading.Thread(target=self._run_task, args=(task,))
            threads.append(thread)
            thread.start()

        for thread in threads:
            thread.join()

    def _run_task(self, task: Task):
        try:
            task.func()
        except Exception as e:
            print(f"Error al ejecutar la tarea '{task.name}': {str(e)}")

