import enum

class TokenType(enum.Enum):
    LITERAL = 1
    UNION = 2
    CONCAT = 3
    ZERO_OR_MORE = 4
    ONE_OR_MORE = 5
    ZERO_OR_ONE = 6
    GROUP = 7
    START = 8
    END = 9

class Token:
    def __init__(self, type, value):
        self.type = type
        self.value = value

    def __repr__(self):
        return f"Token({self.type}, {self.value})"

class Lexer:
    def __init__(self, pattern):
        self.pattern = pattern
        self.pos = 0

    def get_token(self):
        if self.pos >= len(self.pattern):
            return Token(TokenType.END, None)

        if self.pattern[self.pos].isalnum() or self.pattern[self.pos] == '.':
            literal = self.pattern[self.pos]
            self.pos += 1
            return Token(TokenType.LITERAL, literal)

        if self.pattern[self.pos] == '|':
            self.pos += 1
            return Token(TokenType.UNION, '|')

        if self.pattern[self.pos] == '(':
            self.pos += 1
            return Token(TokenType.GROUP, '(')

        if self.pattern[self.pos] == ')':
            self.pos += 1
            return Token(TokenType.GROUP, ')')

        if self.pattern[self.pos] == '*':
            self.pos += 1
            return Token(TokenType.ZERO_OR_MORE, '*')

        if self.pattern[self.pos] == '+':
            self.pos += 1
            return Token(TokenType.ONE_OR_MORE, '+')

        if self.pattern[self.pos] == '?':
            self.pos += 1
            return Token(TokenType.ZERO_OR_ONE, '?')

        raise Exception(f"Caracter no válido: {self.pattern[self.pos]}")

class Parser:
    def __init__(self, lexer):
        self.lexer = lexer
        self.token = self.lexer.get_token()

    def parse(self):
        if self.token.type == TokenType.END:
            return None

        expr = self.parse_expr()

        if self.token.type != TokenType.END:
            raise Exception("Expected end of pattern")

        return expr

    def parse_expr(self):
        term = self.parse_term()

        while self.token.type == TokenType.UNION:
            union_token = self.token
            self.token = self.lexer.get_token()
            term2 = self.parse_term()
            term = (term, union_token.value, term2)

        return term

    def parse_term(self):
        factor = self.parse_factor()

        while self.token.type == TokenType.CONCAT:
            concat_token = self.token
            self.token = self.lexer.get_token()
            factor2 = self.parse_factor()
            factor = (factor, concat_token.value, factor2)

        return factor

    def parse_factor(self):
        if self.token.type == TokenType.LITERAL:
            literal_token = self.token
            self.token = self.lexer.get_token()
            return literal_token.value

        elif self.token.type == TokenType.GROUP:
            group_token = self.token
            self.token = self.lexer.get_token()
            expr = self.parse_expr()

            if self.token.type != TokenType.GROUP:
                raise Exception("Expected closing parenthesis")

            self.token = self.lexer.get_token()
            return expr

        elif self.token.type == TokenType.ZERO_OR_MORE:
            zero_or_more_token = self.token
            self.token = self.lexer.get_token()
            factor = self.parse_factor()
            return (factor, zero_or_more_token.value)

        elif self.token.type == TokenType.ONE_OR_MORE:
            one_or_more_token = self.token
            self.token = self.lexer.get_token()
            factor = self.parse_factor()
            return (factor, one_or_more_token.value)

        elif self.token.type == TokenType.ZERO_OR_ONE:
            zero_or_one_token = self.token
            self.token = self.lexer.get_token()
            factor = self.parse_factor()
            return (factor, zero_or_one_token.value)

        raise Exception(f"Token no válido: {self.token}")

def main():
    pattern = "a*b"
    lexer = Lexer(pattern)
    parser = Parser(lexer)
    result = parser.parse()
    print(result)

