# Definición de tipos de tokens
class TipoToken(enum.Enum):
    LITERAL = 1
    PUNTO = 2
    BARRA_VERTICAL = 3
    PARENTESES_ABRE = 4
    PARENTESES_CIERRA = 5
    ASTERISCO = 6
    MAS = 7
    INTERROGACION = 8
    EOF = 9

# Clase Token
class Token:
    def __init__(self, tipo, valor):
        self.tipo = tipo
        self.valor = valor

    def __repr__(self):
        return f"Token({self.tipo}, {self.valor})"

# Clase Lexer
class Lexer:
    def __init__(self, texto):
        self.texto = texto
        self.posicion = 0

    def obtener_token(self):
        if self.posicion >= len(self.texto):
            return Token(TipoToken.EOF, None)

        caracter = self.texto[self.posicion]

        if caracter.isspace():
            self.posicion += 1
            return self.obtener_token()

        if caracter.isalnum() or caracter in ".-_":
            self.posicion += 1
            return Token(TipoToken.LITERAL, caracter)

        if caracter == ".":
            self.posicion += 1
            return Token(TipoToken.PUNTO, caracter)

        if caracter == "|":
            self.posicion += 1
            return Token(TipoToken.BARRA_VERTICAL, caracter)

        if caracter == "(":
            self.posicion += 1
            return Token(TipoToken.PARENTESES_ABRE, caracter)

        if caracter == ")":
            self.posicion += 1
            return Token(TipoToken.PARENTESES_CIERRA, caracter)

        if caracter == "*":
            self.posicion += 1
            return Token(TipoToken.ASTERISCO, caracter)

        if caracter == "+":
            self.posicion += 1
            return Token(TipoToken.MAS, caracter)

        if caracter == "?":
            self.posicion += 1
            return Token(TipoToken.INTERROGACION, caracter)

        raise Exception(f"Caracter no reconocido: {caracter}")

# Clase Parser
class Parser:
    def __init__(self, lexer):
        self.lexer = lexer
        self.token_actual = self.lexer.obtener_token()

    def obtener_siguiente_token(self):
        self.token_actual = self.lexer.obtener_token()

    def parsear(self):
        if self.token_actual.tipo == TipoToken.EOF:
            return None

        return self.parsear_expresion()

    def parsear_expresion(self):
        resultado = self.parsear_termino()

        while self.token_actual.tipo == TipoToken.BARRA_VERTICAL:
            self.obtener_siguiente_token()
            resultado = (resultado, self.parsear_termino())

        return resultado

    def parsear_termino(self):
        resultado = self.parsear_factor()

        while self.token_actual.tipo == TipoToken.PUNTO:
            self.obtener_siguiente_token()
            resultado = (resultado, self.parsear_factor())

        return resultado

    def parsear_factor(self):
        if self.token_actual.tipo == TipoToken.LITERAL:
            literal = self.token_actual.valor
            self.obtener_siguiente_token()
            return literal

        if self.token_actual.tipo == TipoToken.PARENTESES_ABRE:
            self.obtener_siguiente_token()
            expresion = self.parsear_expresion()

            if self.token_actual.tipo != TipoToken.PARENTESES_CIERRA:
                raise Exception("Parenthesis no cerrado")

            self.obtener_siguiente_token()
            return expresion

        if self.token_actual.tipo == TipoToken.ASTERISCO:
            self.obtener_siguiente_token()
            return "*"

        raise Exception("Token no reconocido")

