from typing import Callable, Dict, List
from functools import wraps

def tarea_con_excepcion(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        try:
            return func(*args, **kwargs)
        except Exception as e:
            print(f"Error en la tarea {func.__name__}: {str(e)}")
    return wrapper

class Task:
    def __init__(self, name: str, func: Callable):
        self.name = name
        self.func = func
        self.dependencies = []

    def add_dependency(self, task: 'Task'):
        self.dependencies.append(task)

class Scheduler:
    def __init__(self):
        self.graph = nx.DiGraph()
        self.tasks: Dict[str, Task] = {}

    def add_task(self, name: str, func: Callable):
        task = Task(name, func)
        self.tasks[name] = task
        self.graph.add_node(name)

    def add_dependency(self, task_name: str, dependency_name: str):
        if task_name not in self.tasks or dependency_name not in self.tasks:
            raise ValueError("Tarea o dependencia no existente")
        task = self.tasks[task_name]
        dependency = self.tasks[dependency_name]
        task.add_dependency(dependency)
        self.graph.add_edge(dependency_name, task_name)

    def schedule(self):
        try:
            # Ordenar tareas por dependencias
            ordered_tasks = list(nx.topological_sort(self.graph))
        except nx.NetworkXUnfeasible:
            print("Error: Ciclo en el grafo de dependencias")
            return

        # Ejecutar tareas de manera concurrente
        threads = []
        for task_name in ordered_tasks:
            task = self.tasks[task_name]
            func = tarea_con_excepcion(task.func)
            thread = threading.Thread(target=func)
            threads.append(thread)
            thread.start()

        # Esperar a que todas las tareas terminen
        for thread in threads:
            thread.join()

